import React, { useMemo, useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  Modal,
  FlatList,
  TextInput,
  StyleSheet,
  Pressable,
  ActivityIndicator,
} from 'react-native';
import { resolveThemeTokenForNative } from '../../Factory/helpers/style';

export type MultiSelectChangeEvent<T> = React.ChangeEvent<{
  value: T[];
}>;

export interface MultiSelectProps<T> {
  value?: T[] | null;
  onChange?: (e: MultiSelectChangeEvent<T>, selectedItems: T[]) => void;
  isModal?: boolean;

  options?: T[];

  optionLabel?: keyof T | string;
  optionValue?: keyof T | string;

  optionGroupLabel?: keyof T | string;
  optionGroupChildren?: keyof T | string;

  placeholder?: string;
  disabled?: boolean;
  loading?: boolean;
  filter?: boolean;
  emptyFilterMessage?: string;

  display?: 'comma' | 'chip';
  maxSelectedLabels?: number;

  itemTemplate?: (item: T) => React.ReactElement;
  selectedItemTemplate?: (item: T) => React.ReactElement;
  style?: import('react-native').ViewStyle;
}

const t = resolveThemeTokenForNative;

const TEXT_STYLE_KEYS = new Set([
  'fontSize', 'fontFamily', 'fontWeight', 'fontStyle',
  'color', 'letterSpacing', 'lineHeight', 'textAlign',
  'textDecorationLine', 'textTransform',
]);

function splitStyle(combined?: any): { viewStyle?: any; textStyle?: any } {
  if (!combined) return {};
  const view: Record<string, any> = {};
  const text: Record<string, any> = {};
  for (const [k, v] of Object.entries(combined)) {
    if (TEXT_STYLE_KEYS.has(k)) text[k] = v;
    else view[k] = v;
  }
  return {
    viewStyle: Object.keys(view).length ? view : undefined,
    textStyle: Object.keys(text).length ? text : undefined,
  };
}

export default function MultiSelect<T>(props: MultiSelectProps<T>) {
  const {
    value,
    onChange,
    options = [],
    optionLabel,
    optionValue,
    optionGroupLabel,
    optionGroupChildren,
    isModal = false,
    placeholder = 'Select',
    disabled,
    loading,
    filter,
    emptyFilterMessage = 'No results found',
    display = 'chip',
    maxSelectedLabels = 10,
    itemTemplate,
    selectedItemTemplate,
    style: externalStyle,
  } = props;

  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState('');

  const { viewStyle: externalViewStyle, textStyle: externalTextStyle } = splitStyle(externalStyle);

  const colors = {
    border: t('border') || t('gray.300'),
    borderFocus: t('primary'),
    bg: t('surface-card') || '#fff',
    disabledBg: t('surface-ground') || t('gray.100'),
    placeholder: t('text-secondary') || t('gray.400'),
    text: t('text') || t('gray.800'),
    textSecondary: t('text-secondary') || t('gray.500'),
    chipBg: t('primary.100') || t('indigo.100'),
    chipText: t('primary.700') || t('indigo.700'),
    chipRemove: t('primary.500') || t('indigo.500'),
    chipMoreBg: t('surface-ground') || t('gray.100'),
    headerBorder: t('border') || t('gray.200'),
    groupBg: t('surface-ground') || t('gray.50'),
    groupBorder: t('border') || t('gray.200'),
    itemBorder: t('surface-ground') || t('gray.100'),
    itemSelectedBg: t('highlight-bg') || t('indigo.50'),
    itemSelectedText: t('primary.700') || t('indigo.700'),
    checkboxBorder: t('border') || t('gray.300'),
    checkboxChecked: t('primary'),
    invalidBorder: t('danger') || t('red.500'),
    searchBg: t('surface-ground') || t('gray.50'),
  };

  const getValue = (item: T, key?: keyof T | string) =>
    key ? (item as any)[key] : item;

  const getLabel = (item: T, key?: keyof T | string) =>
    String(key ? (item as any)[key] : item);

  const selectedValues = Array.isArray(value) ? value : [];

  // Build display items: flat list with optional group headers
  const displayItems: { type: 'group' | 'item'; data: any }[] = useMemo(() => {
    if (optionGroupLabel && optionGroupChildren) {
      const result: { type: 'group' | 'item'; data: any }[] = [];
      options.forEach((group: any) => {
        result.push({ type: 'group', data: group });
        const children = group[optionGroupChildren] ?? [];
        children.forEach((child: any) => result.push({ type: 'item', data: child }));
      });
      return result;
    }
    return options.map((item) => ({ type: 'item' as const, data: item }));
  }, [options, optionGroupLabel, optionGroupChildren]);

  const filtered = useMemo(() => {
    if (!filter || !query) return displayItems;
    return displayItems.filter((entry) => {
      if (entry.type === 'group') return true; // keep group headers
      return getLabel(entry.data, optionLabel)
        .toLowerCase()
        .includes(query.toLowerCase());
    });
  }, [query, displayItems]);

  const isSelected = (item: T) =>
    selectedValues.some(
      (v) => getValue(v, optionValue) === getValue(item, optionValue),
    );

  const toggleItem = (item: T) => {
    const exists = isSelected(item);
    const next = exists
      ? selectedValues.filter(
          (v) => getValue(v, optionValue) !== getValue(item, optionValue),
        )
      : [...selectedValues, item];

    const syntheticEvent = {
      target: { value: next },
    } as React.ChangeEvent<any>;

    onChange?.(syntheticEvent, next);
  };

  const removeItem = (item: T) => {
    const next = selectedValues.filter(
      (v) => getValue(v, optionValue) !== getValue(item, optionValue),
    );
    const syntheticEvent = {
      target: { value: next },
    } as React.ChangeEvent<any>;
    onChange?.(syntheticEvent, next);
  };

  const renderCheckbox = (checked: boolean) => (
    <View
      style={[
        styles.checkbox,
        { borderColor: colors.checkboxBorder, backgroundColor: colors.bg },
        checked && { backgroundColor: colors.checkboxChecked, borderColor: colors.checkboxChecked },
      ]}
    >
      {checked && <Text style={styles.checkmark}>✓</Text>}
    </View>
  );

  const renderListContent = () => {
    if (loading) {
      return (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="small" color={colors.checkboxChecked} />
          <Text style={[styles.loadingText, { color: colors.placeholder }]}>Loading...</Text>
        </View>
      );
    }

    const itemsOnly = filtered.filter((e) => e.type === 'item');
    if (itemsOnly.length === 0) {
      return (
        <View style={styles.emptyContainer}>
          <Text style={[styles.emptyText, { color: colors.placeholder }]}>{emptyFilterMessage}</Text>
        </View>
      );
    }

    return (
      <FlatList
        data={filtered}
        keyExtractor={(entry, i) =>
          entry.type === 'group' ? `group-${i}` : `item-${i}`
        }
        keyboardShouldPersistTaps="handled"
        renderItem={({ item: entry }) => {
          if (entry.type === 'group') {
            return (
              <View style={[styles.groupHeader, { backgroundColor: colors.groupBg, borderBottomColor: colors.groupBorder }]}>
                <Text style={[styles.groupHeaderText, { color: colors.textSecondary }]}>
                  {getLabel(entry.data, optionGroupLabel)}
                </Text>
              </View>
            );
          }
          const checked = isSelected(entry.data);
          return (
            <TouchableOpacity
              onPress={() => toggleItem(entry.data)}
              style={[
                styles.item,
                { borderBottomColor: colors.itemBorder },
                checked && { backgroundColor: colors.itemSelectedBg },
              ]}
              activeOpacity={0.7}
            >
              {renderCheckbox(checked)}
              {itemTemplate ? (
                itemTemplate(entry.data)
              ) : (
                <Text style={[
                  styles.itemText,
                  { color: colors.text },
                  checked && { color: colors.itemSelectedText, fontWeight: '500' },
                ]}>
                  {getLabel(entry.data, optionLabel)}
                </Text>
              )}
            </TouchableOpacity>
          );
        }}
      />
    );
  };

  const renderSelected = () => {
    if (!selectedValues.length) {
      return <Text style={[styles.placeholder, { color: colors.placeholder }, externalTextStyle]}>{placeholder}</Text>;
    }

    if (display === 'chip') {
      const visibleItems = selectedValues.slice(0, maxSelectedLabels);
      const remaining = selectedValues.length - maxSelectedLabels;
      return (
        <View style={styles.chips}>
          {visibleItems.map((item, i) =>
            selectedItemTemplate ? (
              <React.Fragment key={i}>{selectedItemTemplate(item)}</React.Fragment>
            ) : (
              <View key={i} style={[styles.chip, { backgroundColor: colors.chipBg }]}>
                <Text style={[styles.chipText, { color: colors.chipText }]}>{getLabel(item, optionLabel)}</Text>
                <TouchableOpacity
                  onPress={() => removeItem(item)}
                  hitSlop={{ top: 8, bottom: 8, left: 8, right: 8 }}
                >
                  <Text style={[styles.chipRemove, { color: colors.chipRemove }]}>✕</Text>
                </TouchableOpacity>
              </View>
            ),
          )}
          {remaining > 0 && (
            <View style={[styles.chipMore, { backgroundColor: colors.chipMoreBg }]}>
              <Text style={[styles.chipMoreText, { color: colors.textSecondary }]}>+{remaining}</Text>
            </View>
          )}
        </View>
      );
    }

    return (
      <Text numberOfLines={1} style={[styles.commaText, { color: colors.text }, externalTextStyle]}>
        {selectedValues
          .slice(0, maxSelectedLabels)
          .map((v) => getLabel(v, optionLabel))
          .join(', ')}
      </Text>
    );
  };

  const panelContent = (
    <View style={{ flex: 1 }}>
      {/* Header */}
      <View style={[styles.panelHeader, { borderBottomColor: colors.headerBorder }]}>
        <Text style={[styles.panelHeaderText, { color: colors.textSecondary }]}>
          {selectedValues.length} item{selectedValues.length !== 1 ? 's' : ''} selected
        </Text>
        <TouchableOpacity onPress={() => setOpen(false)}>
          <Text style={[styles.panelCloseText, { color: colors.placeholder }]}>✕</Text>
        </TouchableOpacity>
      </View>

      {/* Search */}
      {filter && (
        <View style={[styles.searchContainer, { borderColor: colors.border, backgroundColor: colors.searchBg }]}>
          <Text style={styles.searchIcon}>🔍</Text>
          <TextInput
            value={query}
            onChangeText={setQuery}
            placeholder="Search..."
            style={[styles.searchInput, { color: colors.text }]}
            placeholderTextColor={colors.placeholder}
          />
        </View>
      )}

      {/* List */}
      {renderListContent()}
    </View>
  );

  return (
    <View style={{ width: '100%' }}>
      {/* Input trigger */}
      <TouchableOpacity
        activeOpacity={0.8}
        disabled={disabled}
        onPress={() => setOpen((prev) => !prev)}
        style={[
          styles.input,
          { borderColor: colors.border, backgroundColor: colors.bg },
          disabled && { backgroundColor: colors.disabledBg, opacity: 0.6 },
          open && { borderColor: colors.borderFocus },
          externalViewStyle,
        ]}
      >
        <View style={styles.inputContent}>
          {renderSelected()}
        </View>
        <Text style={[styles.dropdownArrow, { color: colors.placeholder }]}>{open ? '▲' : '▼'}</Text>
      </TouchableOpacity>

      {/* Modal mode */}
      {isModal && (
        <Modal visible={open} transparent animationType="fade">
          <Pressable style={styles.overlay} onPress={() => setOpen(false)}>
            <Pressable style={[styles.modalPanel, { backgroundColor: colors.bg }]} onPress={() => {}}>
              {panelContent}
            </Pressable>
          </Pressable>
        </Modal>
      )}

      {/* Inline mode */}
      {!isModal && open && (
        <View style={StyleSheet.absoluteFill} pointerEvents="box-none">
          <TouchableOpacity
            style={styles.inlineBackdrop}
            activeOpacity={1}
            onPress={() => setOpen(false)}
          />
          <View style={[styles.inlinePanel, { backgroundColor: colors.bg, borderColor: colors.border }]}>
            {panelContent}
          </View>
        </View>
      )}
    </View>
  );
}

